('8e77037b-078f-4e0d-a84e-c2dd195b9871', 'Pleurotus Cornusymphonia (Opera Mushroom) Plant', 'Created by a team of genetic researchers at the University of Rhetor, the opera mushroom is unique in the fungus genus for the various audible tones that it produces. The hollow central chamber of the cap acts as a reverberation chamber amplifying the sounds caused by it''s unique cell structure stretching and compressing as water moves through its mycelium.', NULL, 1, 1, 0, 'Flair_Surface_DisplayCase', 'Ship.Flair.Flair_Surface.Flair_Surface_DisplayCase', ARRAY['SpacePlant'], '{"className":"Flair_Space_Mushroom","reference":"8e77037b-078f-4e0d-a84e-c2dd195b9871","itemName":"flair_space_mushroom","type":"Flair_Surface","subType":"Flair_Surface_DisplayCase","size":1,"grade":1,"name":"Pleurotus Cornusymphonia (Opera Mushroom) Plant","tags":"SpacePlant","classification":"Ship.Flair.Flair_Surface.Flair_Surface_DisplayCase","stdItem":{"UUID":"8e77037b-078f-4e0d-a84e-c2dd195b9871","ClassName":"Flair_Space_Mushroom","Size":1,"Grade":1,"Width":0.15,"Height":0.15,"Length":0.15,"InventoryOccupancy":{"Dimensions":{"Width":0.15,"Length":0.15,"Height":0.15},"UIDimensions":{"Width":0.75,"Length":0.75,"Height":0.75},"Volume":{"SCU":0,"SCUConverted":1,"Unit":"µSCU"}},"Mass":0,"Type":"Flair_Surface.Flair_Surface_DisplayCase","Name":"Pleurotus Cornusymphonia (Opera Mushroom) Plant","Description":"Created by a team of genetic researchers at the University of Rhetor, the opera mushroom is unique in the fungus genus for the various audible tones that it produces. The hollow central chamber of the cap acts as a reverberation chamber amplifying the sounds caused by it’s unique cell structure stretching and compressing as water moves through its mycelium.","DescriptionText":"Created by a team of genetic researchers at the University of Rhetor, the opera mushroom is unique in the fungus genus for the various audible tones that it produces. The hollow central chamber of the cap acts as a reverberatio